UPDATE endpoints r SET current = FALSE WHERE (r.endpoint_id, r.version) NOT IN (SELECT endpoint_id, version FROM current_endpoints);
CREATE INDEX endpoint_id_current_index ON endpoints (endpoint_id, current DESC);
CREATE INDEX endpoint_full_id_index ON endpoints (('Endpoint/' || (endpoint->>'id'))) WHERE current AND deleted IS NULL;
CREATE INDEX endpoint_identifier_index ON endpoints USING GIN ((endpoint->'identifier') jsonb_path_ops) WHERE current AND deleted IS NULL;

ALTER TABLE current_endpoints OWNER TO ${db.liquibase_user};
GRANT ALL ON TABLE current_endpoints TO ${db.liquibase_user};
