UPDATE organization_affiliations r SET current = FALSE WHERE (r.organization_affiliation_id, r.version) NOT IN (SELECT organization_affiliation_id, version FROM current_organization_affiliations);
CREATE INDEX organization_affiliation_id_current_index ON organization_affiliations (organization_affiliation_id, current DESC);
CREATE INDEX organization_affiliation_organization_ref_index ON organization_affiliations ((organization_affiliation->'organization'->>'reference')) WHERE current AND deleted IS NULL;
CREATE INDEX organization_affiliation_participating_organization_ref_index ON organization_affiliations ((organization_affiliation->'participatingOrganization'->>'reference')) WHERE current AND deleted IS NULL;
CREATE INDEX organization_affiliation_endpoint_ref_index ON organization_affiliations ((organization_affiliation->'endpoint'->>'reference')) WHERE current AND deleted IS NULL;

